#!/usr/bin/env node
// Replaces each `<rule>.test.ts` in src/plugin/rules/react-builtins/ with
// a thin shim that drives the rule through the OXC-derived fixtures
// generated by `extract-oxc-fixtures.mjs`. After this codegen runs, each
// rule's test count equals OXC's upstream pass+fail vec entry count.
//
// Tests still owned by hand (e.g. regressions for Bugbot findings) live
// in a sibling `<rule>.regressions.test.ts` file — this script never
// touches `*.regressions.test.ts`.

import * as fs from "node:fs";
import * as path from "node:path";
import { fileURLToPath } from "node:url";

const SCRIPT_DIRECTORY = path.dirname(fileURLToPath(import.meta.url));
const PACKAGE_ROOT = path.resolve(SCRIPT_DIRECTORY, "..");
const RULES_ROOT = path.join(PACKAGE_ROOT, "src/plugin/rules");

// Buckets that have an OXC-derived fixture pipeline. Each must have a
// `__fixtures__/oxc-divergences.ts` and a `__fixtures__/oxc-settings-translators.ts`
// file in its bucket dir.
const BUCKETS = ["react-builtins", "a11y"];

// Inspect the rule .ts file to find the exported variable (`export const xxx = defineRule(...)`)
const findRuleExportName = (ruleFilePath) => {
  const source = fs.readFileSync(ruleFilePath, "utf8");
  const exportMatch = source.match(/export\s+const\s+([A-Za-z_$][\w$]*)\s*=\s*defineRule/);
  return exportMatch ? exportMatch[1] : null;
};

const ruleIdFromRuleFile = (ruleFilePath) => {
  const source = fs.readFileSync(ruleFilePath, "utf8");
  const idMatch = source.match(/^\s*id:\s*"([^"]+)",?\s*$/m);
  return idMatch ? idMatch[1] : null;
};

const main = () => {
  let written = 0;
  for (const bucket of BUCKETS) {
    const bucketRulesDir = path.join(RULES_ROOT, bucket);
    const fixturesDir = path.join(bucketRulesDir, "__fixtures__");
    if (!fs.existsSync(fixturesDir)) continue;
    for (const fixtureFileName of fs.readdirSync(fixturesDir)) {
      if (!fixtureFileName.endsWith(".fixtures.ts")) continue;
      const baseName = fixtureFileName.replace(/\.fixtures\.ts$/, "");
      const ruleFilePath = path.join(bucketRulesDir, `${baseName}.ts`);
      if (!fs.existsSync(ruleFilePath)) continue;
      const exportName = findRuleExportName(ruleFilePath);
      const ruleId = ruleIdFromRuleFile(ruleFilePath);
      if (!exportName || !ruleId) continue;

      const testContent = `// GENERATED — do not edit by hand. Run \`pnpm gen:fixture-tests\` to
// regenerate. Hand-written regression tests live in
// \`${baseName}.regressions.test.ts\` and survive regeneration.

import { runOxcFixtures } from "../../../test-utils/run-fixtures.js";
import { failCases, passCases } from "./__fixtures__/${baseName}.fixtures.js";
import { DIVERGENCES } from "./__fixtures__/oxc-divergences.js";
import { TRANSLATORS } from "./__fixtures__/oxc-settings-translators.js";
import { ${exportName} } from "./${baseName}.js";

const divergence = DIVERGENCES["${ruleId}"];
runOxcFixtures("${bucket}/${ruleId}", ${exportName}, { passCases, failCases }, {
  translateOxcFixture: TRANSLATORS["${ruleId}"],
  knownPassDivergences: divergence?.passSkips,
  knownFailDivergences: divergence?.failSkips,
});
`;
      const testFilePath = path.join(bucketRulesDir, `${baseName}.test.ts`);
      fs.writeFileSync(testFilePath, testContent);
      written += 1;
    }
  }
  console.log(`Wrote ${written} fixture-driven test files.`);
};

main();
